import java.sql.*;

public class SQLInjectionSecure {
    public static void main(String[] args) {
        try {
            String username = args[0]; // Assume user input is directly taken as username

            // Establishing a connection to the database
            Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "root", "password");

            // Creating a PreparedStatement with parameterized query
            String query = "SELECT * FROM users WHERE username=?";
            PreparedStatement pstmt = conn.prepareStatement(query);

            // Setting the parameter value safely
            pstmt.setString(1, username);

            // Executing the query
            ResultSet rs = pstmt.executeQuery();

            // Processing the result set
            while (rs.next()) {
                System.out.println("User ID: " + rs.getInt("id") + ", Username: " + rs.getString("username"));
            }

            conn.close();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

